namespace NotificationsApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<NotificationItem> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.AddRange(new[]
        {
            new NotificationItem { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-30) },
            new NotificationItem { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-15) },
            new NotificationItem { Id = _nextId++, Message = "New feature: Dark mode is available.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
        });

        // Simulate new notifications arriving over time
        _ = GenerateNotificationsAsync();
    }

    public Task<List<NotificationItem>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    public Task<List<NotificationItem>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            var newer = _notifications.Where(n => n.Id > lastSeenId)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
            return Task.FromResult(newer);
        }
    }

    private async Task GenerateNotificationsAsync()
    {
        var messages = new[]
        {
            "Someone liked your post.",
            "You have a new follower.",
            "Your report is ready to download.",
            "Scheduled maintenance tonight at 11 PM.",
            "New comment on your article.",
            "Your subscription renews tomorrow.",
            "Security alert: new login detected.",
        };

        var rng = new Random();
        while (true)
        {
            await Task.Delay(TimeSpan.FromSeconds(rng.Next(8, 20)));
            lock (_lock)
            {
                _notifications.Add(new NotificationItem
                {
                    Id = _nextId++,
                    Message = messages[rng.Next(messages.Length)],
                    Timestamp = DateTime.UtcNow
                });
            }
        }
    }
}

